// ============================================
// v6.2.0: QR CODE PHISHING DETECTION ("QUISHING")
// Decodes QR codes from inline email images and extracts embedded URLs.
// Decoded URLs are fed into the existing analysis pipeline (Phase 1 + Phase 2).
// Viktor: "The QR code is how I get the mailbox. Decode it and you cut me off at the root."
// ============================================
const QR_CONFIG = {
    maxImages: 5,           // v6.2.0: Cap images to decode per email
    minDimension: 100,      // v6.2.0: Skip images smaller than 100px (tracking pixels, icons)
    maxDimension: 1000,     // v6.2.0: Skip images larger than 1000px. Viktor: QR campaigns render at 700-800px.
    aspectRatioMin: 0.8,    // v6.2.0: QR codes are square — skip non-square images
    aspectRatioMax: 1.2,
    decodeTimeoutMs: 500    // v6.2.0: Per-image timeout to prevent hangs from malformed QR
};

// v6.2.0: Decode QR codes from HTML email body (Outlook).
// Parses <img> tags, draws to offscreen canvas, runs jsQR, extracts URLs.
// Returns array of decoded URL strings. Fails silently on CORS/load errors.
// Viktor-test: try/catch + timeout on every image. Malformed QR can't hang the scanner.
async function decodeQRCodesFromHtml(htmlString) {
    const decoded = [];
    if (typeof jsQR !== 'function') {
        console.log('[EFA QR v6.2.0] jsQR library not loaded, skipping QR decode');
        return decoded;
    }
    if (!htmlString) return decoded;

    try {
        const parser = new DOMParser();
        const doc = parser.parseFromString(htmlString, 'text/html');
        const images = Array.from(doc.querySelectorAll('img'));

        let processed = 0;
        for (const imgEl of images) {
            if (processed >= QR_CONFIG.maxImages) break;
            const src = imgEl.src || imgEl.getAttribute('src') || '';
            if (!src) continue;

            try {
                const result = await decodeQRFromImageSrc(src);
                if (result === 'filtered') continue; // v6.2.0 Viktor fix: filtered images don't count toward cap
                if (result) {
                    decoded.push(result);
                    console.log('[EFA QR v6.2.0] Decoded URL from QR code:', result);
                }
            } catch (e) {
                console.log('[EFA QR v6.2.0] Image decode error:', e.message);
            }
            processed++; // Only counts images that attempted actual QR decode
        }
    } catch (e) {
        console.log('[EFA QR v6.2.0] HTML parsing error:', e.message);
    }

    return decoded;
}

// v6.2.0: Load a single image src, draw to canvas, attempt jsQR decode.
// Returns URL string if QR code found with http(s) URL, null otherwise.
// Viktor-test: 500ms timeout per image. CORS errors caught and skipped.
function decodeQRFromImageSrc(src) {
    return new Promise((resolve) => {
        const timeout = setTimeout(() => {
            console.log('[EFA QR v6.2.0] Timeout decoding image, skipping');
            resolve(null);
        }, QR_CONFIG.decodeTimeoutMs);

        const img = new Image();
        img.crossOrigin = 'anonymous';

        img.onload = () => {
            clearTimeout(timeout);
            try {
                const w = img.naturalWidth;
                const h = img.naturalHeight;

                // v6.2.0: Size filter — skip tracking pixels and hero banners
                if (w < QR_CONFIG.minDimension || h < QR_CONFIG.minDimension) { resolve('filtered'); return; }
                if (w > QR_CONFIG.maxDimension || h > QR_CONFIG.maxDimension) { resolve('filtered'); return; }

                // v6.2.0: Aspect ratio filter — QR codes are square
                const ratio = w / h;
                if (ratio < QR_CONFIG.aspectRatioMin || ratio > QR_CONFIG.aspectRatioMax) { resolve('filtered'); return; }

                // v6.2.0: Draw to offscreen canvas and extract pixel data
                const canvas = document.createElement('canvas');
                canvas.width = w;
                canvas.height = h;
                const ctx = canvas.getContext('2d');
                ctx.drawImage(img, 0, 0);
                const imageData = ctx.getImageData(0, 0, w, h);

                // v6.2.0: Run jsQR decoder
                const qrResult = jsQR(imageData.data, w, h);
                if (qrResult && qrResult.data) {
                    const data = qrResult.data.trim();
                    // Viktor-test: Only treat as URL if starts with http:// or https://.
                    // Discard vCard, Wi-Fi, plain text, etc. Can't be used for phishing without a URL.
                    if (/^https?:\/\//i.test(data)) {
                        resolve(data);
                        return;
                    }
                }
                resolve(null);
            } catch (e) {
                // v6.2.0: Canvas tainted by CORS or other error — skip silently
                console.log('[EFA QR v6.2.0] Canvas error:', e.message);
                resolve(null);
            }
        };

        img.onerror = () => {
            clearTimeout(timeout);
            resolve(null); // v6.2.0: Image load failure — skip silently
        };

        img.src = src;
    });
}

// v6.2.0: Analyze decoded QR URLs against existing detection pipeline.
// Runs lookalike, suspicious domain, free hosting, fake TLD, brand mismatch, and reputation checks.
// Returns array of warning objects (type: 'qr-phishing') for any flagged URLs.
// Viktor-test: No trust bypass. Compromised trusted mailbox sending QR phishing is the VEC play.
async function analyzeQRUrls(qrUrls, senderDomain, senderEmail, brandResult) {
    const qrWarnings = [];
    for (const qrUrl of qrUrls) {
        let qrDomain = '';
        try { qrDomain = new URL(qrUrl).hostname.toLowerCase(); } catch (e) { continue; }

        const qrFlags = []; // v6.2.0: Collect all reasons this QR URL is suspicious

        // v6.2.0: Lookalike domain check (Levenshtein)
        const lookalike = detectLookalikeDomain(qrDomain);
        if (lookalike) qrFlags.push('lookalike of ' + (lookalike.trustedDomain || lookalike));

        // v6.2.0: Suspicious domain check (high-risk TLDs, fake country-code combos)
        const suspicious = detectSuspiciousDomain(qrDomain);
        if (suspicious) qrFlags.push(suspicious.reason || 'suspicious domain characteristics');

        // v6.2.0: Free hosting platform check
        const freeHosting = detectFreeHostingSender(qrDomain);
        if (freeHosting) qrFlags.push('free hosting platform: ' + freeHosting.hostingPlatform);

        // v6.2.0: Fake TLD check
        const fakeTld = detectFakeTLD(qrDomain);
        if (fakeTld) qrFlags.push('fake domain extension: ' + fakeTld.fakeTLD);

        // v6.2.0: Brand mismatch — QR URL goes to domain that doesn't match claimed brand
        let isBrandMismatch = false;
        if (brandResult) {
            const isLegitBrandUrl = brandResult.legitimateDomains.some(ld =>
                qrDomain === ld || qrDomain.endsWith('.' + ld));
            if (!isLegitBrandUrl) {
                qrFlags.push('QR link does not match claimed brand ' + brandResult.brandName);
                isBrandMismatch = true;
            }
        }

        // v6.2.0: Sender-link mismatch — QR URL goes to unrelated domain.
        // Viktor-test: Booster signal only — cannot fire a warning by itself.
        // Legitimate newsletters routinely use QR codes pointing to CDNs or tracking
        // domains that don't match the sender. Requiring a hard signal (lookalike, fake TLD,
        // free hosting, brand mismatch, suspicious domain, or reputation) eliminates
        // false positives while still escalating severity when a real attack uses a
        // suspicious unrelated domain. Viktor can still be caught because his payload
        // domain almost always has at least one additional hard signal.
        let hasUnrelatedDomain = false;
        if (qrDomain !== senderDomain && !qrDomain.endsWith('.' + senderDomain) && !senderDomain.endsWith('.' + qrDomain)) {
            const isKnownBrandUrl = isOfficialBrandDomain(qrDomain);
            const isKnownPlatformUrl = isKnownPlatform(qrDomain);
            if (!isKnownBrandUrl && !isKnownPlatformUrl) {
                hasUnrelatedDomain = true; // v6.2.0: Track separately — add to flags only if other signals present
            }
        }
        if (hasUnrelatedDomain && qrFlags.length > 0) {
            qrFlags.push('links to unrelated domain'); // v6.2.0: Booster — amplifies existing flags, doesn't fire alone
        }

        // v6.2.0: Domain reputation check (threat feeds + WHOIS age via Cloudflare Worker)
        try {
            const qrReputation = await checkDomainReputation(qrDomain);
            if (qrReputation) {
                if (qrReputation.layer === 'threat_feed') qrFlags.push('known malicious domain');
                if (qrReputation.layer === 'whois_age') qrFlags.push('newly registered domain (' + qrReputation.domainAge + ' days old)');
            }
        } catch (e) {
            console.log('[EFA QR v6.2.0] Reputation check failed for', qrDomain, ':', e.message);
        }

        if (qrFlags.length > 0) {
            const hasCriticalFlag = !!(lookalike || fakeTld || isBrandMismatch || freeHosting);
            qrWarnings.push({
                type: 'qr-phishing',
                severity: hasCriticalFlag ? 'critical' : 'high',
                title: 'QR Code Contains Suspicious Link',
                description: 'This email contains a QR code that links to ' + qrDomain + '. Scanning this code would take you to a potentially dangerous website. Do not scan QR codes from unexpected emails.',
                senderEmail: senderEmail,
                qrUrl: qrUrl,
                qrDomain: qrDomain,
                qrFlags: qrFlags
            });
            console.log('[EFA QR v6.2.0] FLAGGED QR URL:', qrUrl, '| Flags:', qrFlags.join(', '));
        }
    }
    return qrWarnings;
}

